PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?duration
WHERE {
  {
    ?game wdt:P2667 wd:Q15933 ;
          wdt:P2668 wd:Q22205 ;
          wdt:P178 ?event .
  }
  UNION
  {
    ?game wdt:P2667 wd:Q22205 ;
          wdt:P2668 wd:Q15933 ;
          wdt:P178 ?event .
  }
  ?event wdt:P580 ?start_date .
  ?game wdt:P2513 ?duration .
  FILTER (year(?start_date) IN (1977, 1978, 2008, 2009))
}
ORDER BY DESC(?duration)
OFFSET 2
LIMIT 1

